style.css:
@import url(https://fonts.bunny.net/css?family=jura:300,500);

@layer base, cards;

@layer cards {
	:root {
		--carousel-duration: 30s;
		--carousel-depth: 180px;
		--card-width: 80px;
		--card-height: 120px;

  	@media (width > 600px) {
			--carousel-depth: 330px;
			--card-width: 120px;
			--card-height: 180px;
		}
	}

	body {
		perspective: 1000px;
		overflow: hidden;
	}

	.carousel {
    /* total number of elements */
    --card-count: sibling-count();
    @supports not (order: sibling-index()) {
      /* fallback for browsers that don't support sibling-index*/
      --card-count: 9;
    }

		transform-style: preserve-3d;
		position: absolute;
		inset: 0;
		margin: auto;

		/* pause carsousel when card gets hover */
		&:has(.card:hover) .card {
			animation-play-state: paused;
		}
		&:has(.card:hover) .card:not(:hover) > *  {
			opacity: .25;
		}

	}
@property --reflect-distance {
  syntax: "<length>";
  initial-value: 5px;
  inherits: false;
}

	.card {
    /* get card index */
    --i: sibling-index();
     @supports not (order: sibling-index()) {
      /* fallback for browsers that don't support sibling-index
       you will need to create 
       */
      &:nth-child(1) { --i: 1;}
  		&:nth-child(2) { --i: 2;}
  		&:nth-child(3) {--i: 3;}
  		&:nth-child(4) { --i: 4;}
  		&:nth-child(5) {  --i: 5;}
  		&:nth-child(6) { --i: 6;}
  		&:nth-child(7) { --i: 7;}
  		&:nth-child(8) { --i: 8;}
  		&:nth-child(9) { --i: 9;}
  		&:nth-child(10) { --i: 10;}
    }

		--angle: calc((360deg / var(--card-count)) * var(--i));
		--delay: calc((-1 * var(--carousel-duration) / var(--card-count)) * var(--i));

		--hover-duration: 300ms;
		--hover-easing: linear(0, 0.708 15.2%, 0.927 23.6%, 1.067 33%, 1.12 41%, 1.13 50.2%, 1.019 83.2%, 1);


		position: absolute;
		top: 50%;
		left: 50%;
		width: var(--card-width);
		height: var(--card-height);
		transform-style: preserve-3d;
		transform: translate(-50%, -50%) rotateY(var(--angle))
			translateZ(var(--carousel-depth));
		opacity: 1;
		scale: 1;
		display: grid;
		place-content: end;
		perspective: 500px;

    animation-name: orbit-x;
		animation-duration: var(--carousel-duration);
		animation-timing-function: linear;
		animation-iteration-count: infinite;
		animation-delay: var(--delay);

		transition:  var(--hover-duration) var(--hover-easing) var(--hover-duration);

    /*  reflection */
    -webkit-box-reflect: below var(--reflect-distance) linear-gradient(to top, rgba(0 0 0 / .15) 25%, transparent);

		&:hover{

			& > img{
				scale: 1.2;
			}
		}

    & > img{
      width: 100%;
      height: 100%;
      object-fit: cover;
			transition: scale var(--hover-duration) var(--hover-easing);
			/*transition-delay: -300ms;*/
    }

		&[data-title="Thor"]{
			transition-duration: 300ms;
			transition-delay: 2s;
			transition-timing-function: linear(0, 0.708 15.2%, 0.927 23.6%, 1.067 33%, 1.12 41%, 1.13 50.2%, 1.019 83.2%, 1);
			/* drop Thor in from above - issue with reflection :thinking: */
			@starting-style{
				translate: 0 -1000px;
				 --reflect-distance: 200px;
			}
		}
		&[data-title="Hulk"]{

		place-content: center;
			& > img{
				scale: 1.8;
				 object-fit: contain;

				&:hover{
					scale: 2.2;
				}
			}
		}
    /*borders*/
		/*
		&::before{
			content: '';
			position: absolute;
			bottom: 0;
			left: 50%;
			translate: -50% 0;
			width: 75%;
			height: 75%;
			z-index: -1;
			background: rgba(2  6 24 / .5);
			border: 1px solid rgba(255 255 255 / .5);
			transform: translatey(-200px);
			border-top: none
		}
		*/
    /* labels */
    &::after{
      content: attr(data-title);
      position: absolute;
      bottom: 100%;
      left: 50%;
      transform: translateX(-50%);
      color: white;
      font-size: .7rem;
      text-wrap: nowrap;
      opacity: 0;
      translate: 0 50px;
			padding: .25em .75em;
			background: rgba(255 255 255 / .15);
			border: 1px solid rgba(255 255 255 / .5);

      animation-name: orbit-x-labels;
  		animation-duration: var(--carousel-duration);
  		animation-timing-function: linear;
  		animation-iteration-count: infinite;
  		animation-delay: var(--delay);
    }

	}

	/* rotation - horizontal */
	@keyframes orbit-x {
		0% {
			transform: translate(-50%, -50%) rotateY(0deg)
				translateZ(var(--carousel-depth));
			opacity: 1;
			scale: 1;
		}
		25%,
		75% {
			opacity: 0.75;
			scale: 0.85;
		}
		50% {
			opacity: 0.4;
			scale: 0.75;
		}
		100% {
			transform: translate(-50%, -50%) rotateY(360deg)
				translateZ(var(--carousel-depth));
			opacity: 1;
			scale: 1;
		}
	}

  @keyframes orbit-x-labels {
		25%,75%{
      opacity: 0;
       translate: 0 20px;
    }
    100%,0% {
      opacity: 1;
      translate: 0 0;
		}
	}
}

/* general styling not relevant for this demo */
@layer base {
	* {
		box-sizing: border-box;
	}
	:root {
		color-scheme: light dark;
		--bg-dark: rgb(24, 24, 27);
		--bg-light: rgb(231, 229, 228);

		--txt-light: rgb(10, 10, 10);
		--txt-dark: rgb(245, 245, 245);
	}

	body {
		background-color: var(--bg-dark);
		color: var(--txt-dark);
		min-height: 100svh;
		margin: 0;
		padding: 1rem 2rem;
		font-size: 1rem;
		font-family: "Jura", sans-serif;
		line-height: 1.5;
		display: grid;
		place-content: center;
		gap: 1rem;
	}
  .msg-supports {
		font-size: 0.8rem;
		@supports (order: sibling-index()) {
			display: none;
		}
	}
}
